def main():
    for slug, data in MISSING.items():
        out = PAPER_DATA_DIR / f"{slug}.json"
        with open(out, 'w') as f:
            json.dump(data, f, indent=2)
        print(f"  ✓ {slug}.json ({len(data.get('keyFindings', []))} findings)")

    print(f"\nWrote {len(MISSING)} JSON files to {PAPER_DATA_DIR}")

    # Now regenerate PPTX for these 4
    sys.path.insert(0, str(Path(__file__).parent))
    from generate_pptx import generate_pptx

    with ThreadPoolExecutor(max_workers=4) as executor:
        futures = {executor.submit(generate_pptx, PAPER_DATA_DIR / f"{s}.json"): s for s in MISSING}
        for future in futures:
            slug, slides, path = future.result()
            print(f"  ✓ {slug}: {slides} slides")

if __name__ == "__main__":
    main()
